.sig-minimal-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(21,27,29,0.16);
  border-radius: 10px;
  background: linear-gradient(145deg, #f7f8f5, #ecefeb);
  color: #151b1d;
  box-shadow: 0 24px 64px rgba(0,0,0,0.18);
  font-family: Inter, ui-sans-serif, system-ui, sans-serif;
}
.sig-minimal-hero::before { content: ""; position: absolute; inset: 0; background: linear-gradient(180deg, transparent, rgba(21,27,29,0.035)); background-size: auto; opacity: 0.78; pointer-events: none; }
.sig-minimal-hero > * { position: relative; z-index: 1; }
.sig-minimal-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-minimal-hero .kicker { width: fit-content; border: 1px solid rgba(21,27,29,0.16); border-radius: 999px; padding: 6px 10px; color: #111719; background: #ecefeb; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-minimal-hero h1 { margin: 0; max-width: 620px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-minimal-hero p { margin: 0; max-width: 560px; color: #667174; font-size: 15px; line-height: 1.78; }
.sig-minimal-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-minimal-hero button { height: 40px; padding: 0 16px; border-radius: calc(10px / 2 + 4px); border: 1px solid rgba(21,27,29,0.16); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-minimal-hero .primary { background: #111719; color: #f7f8f5; border-color: #111719; }
.sig-minimal-hero .secondary { background: transparent; color: #151b1d; }
.sig-minimal-hero button:hover { transform: translateY(-1px); border-color: #111719; }
.sig-minimal-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(21,27,29,0.16); border-radius: calc(10px - 2px); background: #ecefeb; backdrop-filter: blur(18px) saturate(140%); }
.sig-minimal-hero .artifact h2 { margin: 0; font-size: 13px; color: #111719; text-transform: uppercase; letter-spacing: 0; }
.sig-minimal-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-minimal-hero .metric { padding: 14px; border: 1px solid rgba(21,27,29,0.16); border-radius: calc(10px - 4px); background: color-mix(in srgb, #f7f8f5 76%, transparent); }
.sig-minimal-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-minimal-hero .metric span { display: block; margin-top: 6px; color: #667174; font-size: 11px; }
.sig-minimal-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #111719, #526f7b); }
@media (max-width: 780px) { .sig-minimal-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-minimal-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(21,27,29,0.16); border-radius: 10px; background: #f7f8f5; color: #151b1d; box-shadow: 0 24px 64px rgba(0,0,0,0.18); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-minimal-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-minimal-card .label { color: #111719; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-minimal-card .pill { border: 1px solid rgba(21,27,29,0.16); border-radius: 999px; padding: 5px 9px; color: #667174; background: #ecefeb; font-size: 11px; }
.sig-minimal-card h3 { margin: 0 0 10px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-minimal-card p { margin: 0; color: #667174; font-size: 13px; line-height: 1.7; }
.sig-minimal-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(21,27,29,0.16); }
.sig-minimal-card .strip strong { font-variant-numeric: tabular-nums; color: #151b1d; }
.sig-minimal-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(10px - 4px); background: #111719; color: #f7f8f5; font-weight: 900; }

.sig-minimal-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(21,27,29,0.16); border-radius: 10px; background: #f7f8f5; color: #151b1d; box-shadow: 0 24px 64px rgba(0,0,0,0.18); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-minimal-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-minimal-nav .mark { width: 30px; height: 30px; border-radius: calc(10px - 4px); background: linear-gradient(135deg, #111719, #526f7b); box-shadow: inset 0 0 0 1px rgba(21,27,29,0.16); }
.sig-minimal-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-minimal-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(10px - 6px); color: #667174; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-minimal-nav a:hover, .sig-minimal-nav a.active { color: #151b1d; background: #ecefeb; }
.sig-minimal-nav button { height: 34px; padding: 0 13px; border-radius: calc(10px - 6px); border: 1px solid #111719; background: #111719; color: #f7f8f5; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-minimal-nav { align-items: stretch; flex-direction: column; } }

.sig-minimal-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(21,27,29,0.16); border-radius: 10px; background: #f7f8f5; color: #151b1d; box-shadow: 0 24px 64px rgba(0,0,0,0.18); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-minimal-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #151b1d; }
.sig-minimal-form small { color: #667174; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-minimal-form .row { display: flex; gap: 10px; }
.sig-minimal-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(10px - 6px); border: 1px solid rgba(21,27,29,0.16); background: #ecefeb; color: #151b1d; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-minimal-form input:focus { border-color: #111719; box-shadow: 0 0 0 3px color-mix(in srgb, #111719 18%, transparent); }
.sig-minimal-form button { height: 42px; padding: 0 14px; border-radius: calc(10px - 6px); border: 1px solid #111719; background: #111719; color: #f7f8f5; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-minimal-form .row { flex-direction: column; } }

.sig-minimal-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(21,27,29,0.16); border-radius: 10px; background: #f7f8f5; color: #151b1d; box-shadow: 0 24px 64px rgba(0,0,0,0.18); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-minimal-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-minimal-table th, .sig-minimal-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(21,27,29,0.16); }
.sig-minimal-table th { color: #667174; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: #ecefeb; }
.sig-minimal-table td { color: #151b1d; }
.sig-minimal-table tr:last-child td { border-bottom: 0; }
.sig-minimal-table tbody tr:hover td { background: #ecefeb; }
.sig-minimal-table .mono { font-variant-numeric: tabular-nums; }
.sig-minimal-table .status { display: inline-flex; align-items: center; gap: 6px; color: #111719; font-weight: 800; }
.sig-minimal-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #111719; }
